_active = None

def agent(obs):
    global _active
    if _active is None:
        from orbit_lite.adapter import single_obs_to_tensor
        from orbit_lite.planner_core import largest_initial_player_count
        player_id = int(obs.get("player", 0) if isinstance(obs, dict) else obs.player)
        obs_t = single_obs_to_tensor(obs, player_id=player_id)
        pc = largest_initial_player_count(obs_t)
        _active = _mod_2p if pc == 2 else _mod_mp
    return _active.agent(obs)
